#!/usr/bin/env node
require("dotenv").config();const fetch=require("node-fetch"),path=require("path"),CSVReader=require("./utils/csvReader"),DiscordNotifier=require("./services/discordNotifier"),NFTTracker=require("./services/nftTracker"),config=require("./config");function toChecksum(address){return String(address||"").toLowerCase()}async function getTrackedWalletSet(csvPath){const csvReader=new CSVReader(csvPath),wallets=await csvReader.readWallets(),set=new Set(wallets.map((w=>toChecksum(w.address))));return{wallets:wallets,set:set}}const CHAIN_APIS={Ethereum:"https://api.etherscan.io",Base:"https://api.basescan.org",Polygon:"https://api.polygonscan.com",Arbitrum:"https://api.arbiscan.io",Optimism:"https://api-optimistic.etherscan.io",BSC:"https://api.bscscan.com",Avalanche:"https://api.snowtrace.io",Berachain:"https://api.berascan.com",Abstract:"https://api.abstract.money"},ERC721_TRANSFER_SIG="0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef",ERC1155_SINGLE_SIG="0xc3d58168c5ae7397731d063d5bbf3d657854427343f4c083240f7aacaa2d0f62",ERC1155_BATCH_SIG="0x4a39dc06d4c0dbc64b70b48d78a0360a7a222ff32b9f1e9d0a6a5d1d0f8f8f7d";function hexToAddress(topic){return topic?"0x"+topic.slice(-40).toLowerCase():null}function hexToBigInt(hex){try{return BigInt(hex)}catch{return 0n}}async function findReceiptAcrossChains(txHash){const abstractRpc=process.env.ABSTRACT_RPC_URL;if(abstractRpc)try{const body={jsonrpc:"2.0",id:1,method:"eth_getTransactionReceipt",params:[txHash]},res=await fetch(abstractRpc,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)}),data=await res.json();if(data&&data.result&&data.result.logs)return{chainName:"Abstract",baseUrl:abstractRpc,receipt:data.result,rpcUrl:abstractRpc}}catch(e){}for(const[chainName,baseUrl]of Object.entries(CHAIN_APIS))try{const url=`${baseUrl}/api?module=proxy&action=eth_getTransactionReceipt&txhash=${txHash}&apikey=${config.etherscan.apiKey||""}`,res=await fetch(url),data=await res.json();if(data&&data.result&&data.result.logs)return{chainName:chainName,baseUrl:baseUrl,receipt:data.result}}catch(e){}return null}async function main(){const txHash=process.argv[2]||process.env.TX_HASH,forceTo=(process.argv[3]||process.env.FORCE_TO||"").toLowerCase();txHash||(console.error("Usage: node notify-from-tx.js <txHash> [toAddress]"),process.exit(1));const notifier=new DiscordNotifier,tracker=new NFTTracker,{set:trackedSet}=await getTrackedWalletSet(config.csvFile),found=await findReceiptAcrossChains(txHash);found||(console.error("❌ Could not find transaction receipt on supported chains"),process.exit(2));const{chainName:chainName,receipt:receipt}=found,mintedItems=[];for(const log of receipt.logs){const sig=log.topics&&log.topics[0]?log.topics[0].toLowerCase():"";if(sig===ERC721_TRANSFER_SIG&&log.topics.length>=4){const from=hexToAddress(log.topics[1]),to=hexToAddress(log.topics[2]),matchTo=forceTo?to===forceTo:trackedSet.has(to);if("0x0000000000000000000000000000000000000000"===from&&matchTo){const tokenId=hexToBigInt(log.topics[3]).toString();mintedItems.push({standard:"ERC721",contract:log.address,to:to,tokenId:tokenId,quantity:1})}}else if(sig===ERC1155_SINGLE_SIG&&log.topics.length>=4){const to=hexToAddress(log.topics[3]);if(forceTo?to===forceTo:trackedSet.has(to)){const data=log.data||"0x",id="0x"+data.slice(2).slice(0,64),valueHex="0x"+data.slice(2).slice(64,128);mintedItems.push({standard:"ERC1155",contract:log.address,to:to,tokenId:hexToBigInt(id).toString(),quantity:Number(hexToBigInt(valueHex))||1})}}else if(sig===ERC1155_BATCH_SIG&&log.topics.length>=4){const to=hexToAddress(log.topics[3]);if(forceTo?to===forceTo:trackedSet.has(to)){const data=log.data.slice(2),readBigInt=offset=>hexToBigInt("0x"+data.slice(offset,offset+64));let offset=0;const idsOffset=Number(readBigInt(offset));offset+=64;const valuesOffset=Number(readBigInt(offset));offset+=64;const idsStart=64*(Number(readBigInt(idsOffset))+1),idsLen=Number(readBigInt(idsOffset));let ids=[];for(let i=0;i<idsLen;i++){const hex="0x"+data.slice(idsStart+64*i,idsStart+64*(i+1));ids.push(hexToBigInt(hex).toString())}const valsStart=64*(Number(readBigInt(valuesOffset))+1),valsLen=Number(readBigInt(valuesOffset));let vals=[];for(let i=0;i<valsLen;i++){const hex="0x"+data.slice(valsStart+64*i,valsStart+64*(i+1));vals.push(Number(hexToBigInt(hex))||1)}ids.forEach(((id,i)=>mintedItems.push({standard:"ERC1155",contract:log.address,to:to,tokenId:id,quantity:vals[i]||1})))}}}0===mintedItems.length&&(console.error("ℹ️ No mint events to tracked wallets found in this transaction."),process.exit(0));let totalPrice=0;try{if("Abstract"===chainName&&process.env.ABSTRACT_RPC_URL){const body={jsonrpc:"2.0",id:1,method:"eth_getTransactionByHash",params:[txHash]},res=await fetch(process.env.ABSTRACT_RPC_URL,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)}),data=await res.json();data&&data.result&&data.result.value&&(totalPrice=Number(hexToBigInt(data.result.value))/Math.pow(10,18))}else{const res=await fetch(`${CHAIN_APIS[chainName]}/api?module=proxy&action=eth_getTransactionByHash&txhash=${txHash}&apikey=${config.etherscan.apiKey||""}`),data=await res.json();data&&data.result&&data.result.value&&(totalPrice=Number(hexToBigInt(data.result.value))/Math.pow(10,18))}}catch{}const representative=mintedItems[0],floor=await tracker.getFloorPrice(representative.contract,chainName,null),quantity=mintedItems.reduce(((sum,it)=>sum+(it.quantity||1)),0),walletAddress=mintedItems[0].to,txData={type:"mint",isBulk:quantity>1,walletName:walletAddress,walletAddress:walletAddress,tokenName:"Unknown",tokenId:"0x"+BigInt(mintedItems[0].tokenId).toString(16),contractAddress:representative.contract,transactionHash:txHash,chainName:chainName,timestamp:new Date,totalPrice:totalPrice,quantity:quantity,imageUrl:null,nftName:null,nativeSymbol:"ETH",floorPrice:floor||"-"};try{const meta=await tracker.getNFTMetadata(representative.contract,mintedItems[0].tokenId,chainName);meta&&(txData.imageUrl=meta.imageUrl,txData.nftName=meta.name,txData.tokenName=meta.name||txData.tokenName)}catch{}console.log("📤 Sending manual mint notification from tx..."),await notifier.connect(),await new Promise((r=>setTimeout(r,800))),await notifier.sendNotification(txData,tracker),await notifier.disconnect(),console.log("✅ Sent.")}main().catch((err=>{console.error(err),process.exit(1)}));